// 1. Gemini'den gelen ham metni al
const geminiResponse = $input.first().json.content || $input.first().json.response || $input.first().json;
const rawText = geminiResponse.parts ? geminiResponse.parts[0].text : (geminiResponse.text || JSON.stringify(geminiResponse));

// 2. Markdown temizliği
const cleanJson = rawText.replace(/```json/g, '').replace(/```/g, '').trim();

let ocrData;
try {
    ocrData = JSON.parse(cleanJson);
} catch (e) {
    console.log("JSON Parse Hatası:", e.message);
    ocrData = {
        IsletmeAdi: "Okunamadı",
        ToplamTutar: 0,
        Tarih: null,
        Saat: null,
        OdemeTipi: null,
        UrunlerVeKDVBilgileri: []
    };
}

// 3. TARİH VE SAAT FORMATLAMA
function normalizeDate(dateStr) {
    if (!dateStr) return new Date().toISOString().split('T')[0];
    const yyyyMatch = dateStr.match(/^(\d{4})[./-](\d{1,2})[./-](\d{1,2})/);
    if (yyyyMatch) {
        const year = yyyyMatch[1];
        const month = yyyyMatch[2].padStart(2, '0');
        const day = yyyyMatch[3].padStart(2, '0');
        return `${year}-${month}-${day}`;
    }
    const ddmmyyyyMatch = dateStr.match(/^(\d{1,2})[./-](\d{1,2})[./-](\d{4})/);
    if (ddmmyyyyMatch) {
        const day = ddmmyyyyMatch[1].padStart(2, '0');
        const month = ddmmyyyyMatch[2].padStart(2, '0');
        const year = ddmmyyyyMatch[3];
        return `${year}-${month}-${day}`;
    }
    return new Date().toISOString().split('T')[0];
}

function normalizeTime(timeStr) {
    if (!timeStr) return "00:00:00";
    if (timeStr.match(/^\d{1,2}:\d{2}$/)) {
        return timeStr + ":00";
    }
    return timeStr;
}

// 4. OTOMATİK KATEGORİ BELİRLEME
let mainCategory = 'Genel';
const items = ocrData.UrunlerVeKDVBilgileri || [];
if (items.length > 0) {
    const categories = items.map(item => item.Kategori).filter(c => c && c.trim() !== '');
    const uniqueCategories = [...new Set(categories)];
    if (uniqueCategories.length === 1) {
        mainCategory = uniqueCategories[0];
    } else if (uniqueCategories.length > 1) {
        mainCategory = 'Çoklu';
    }
}

