};

// OCR sonucunu al
const ocrResult = $json.responses?.[0]?.textAnnotations?.[0]?.description || '';

if (!ocrResult || ocrResult.trim().length < 10) {
  return [{ json: { isFis: false, reason: 'OCR sonucu boş veya çok kısa' } }];
}

const ocrText = ocrResult.toLowerCase();

const fisKeywords = [
  'kdv', 'KDV', 'toplam', 'tutar', 'fiş', 'fis', 'fatura', 'ödeme',
  'kart', 'nakit', 'tarih', 'saat', 'matrah', 'vergi', 'iade',
  'para üstü', 'paraustu', 'bakiye', 'kasa', 'satış', 'ürün',
  'adet', 'birim', 'fiyat'
];

const hasNumbers = /\d+[.,]?\d*/.test(ocrText);
const hasDate = /\d{1,2}[./]\d{1,2}[./]\d{2,4}/.test(ocrText);

let keywordCount = 0;
for (const keyword of fisKeywords) {
  if (ocrText.includes(keyword)) {
    keywordCount++;
  }
}

const isFis = keywordCount >= 3 && hasNumbers;

let reason = '';
if (!isFis) {
  if (keywordCount < 3) {
    reason = `Fişe özgü kelime sayısı yetersiz (${keywordCount}/3)`;
  } else if (!hasNumbers) {
    reason = 'Sayısal değer (fiyat) bulunamadı';
  } else {
    reason = 'Fiş kriterlerini karşılamıyor';
  }
}

return [{ 
  json: { 
    ...$json,
    isFis: isFis,
    reason: reason,
    keywordCount: keywordCount,
    hasNumbers: hasNumbers,
    hasDate: hasDate
  } 
}];

const data = $input.first().json.callback_query.data;
const parts = data.split('_');

// Callback mesajının text'inden email'i çıkar
const messageText = $input.first().json.callback_query.message.text || '';
const emailMatch = messageText.match(/Mail:\s*(\S+@\S+)/i);
const email = emailMatch ? emailMatch[1] : '';

// Rastgele Güçlü Şifre Üretimi
const randomString = Math.random().toString(36).slice(-8);
const finalPassword = randomString + 'Aa1!';

return {
  json: {
    action: parts[0],
    company_id: parts[1],
    admin_chat_id: parts[2],
    email: email,
    generated_password: finalPassword
  }
};

