  "Giyim", "Kırtasiye", "Teknoloji", "Temizlik",
  "Temsil ve Ağırlama", "Diğer"
];

const activeCategories = dbCategories.length > 0 ? dbCategories : defaultCategories;
const categoryListString = JSON.stringify(activeCategories);

// 2. VERİLERİ TOPLA
let userNote = "";
let ocrText = ""; 
let originalData = {};

try {
    let triggerNode;
    try { triggerNode = $('fis gonder').first(); } catch(e) {}
    if (!triggerNode) { try { triggerNode = $('Telegram Trigger').first(); } catch(e) {} }
    if (!triggerNode) { try { triggerNode = $('Webhook').first(); } catch(e) {} }

    if (triggerNode) {
        userNote = triggerNode.json.message?.caption || 
                   triggerNode.json.body?.caption || 
                   "";
        originalData = triggerNode.json;
    }

    try {
        const ocrNode = $('Gemini OCR').first();
        if (ocrNode.json.responses && ocrNode.json.responses[0]?.textAnnotations?.[0]?.description) {
            ocrText = ocrNode.json.responses[0].textAnnotations[0].description;
        }
        else if (ocrNode.json.description) { ocrText = ocrNode.json.description; }
        else if (ocrNode.json.text) { ocrText = ocrNode.json.text; }
        if (!ocrText) ocrText = $input.first().json.description || "";
    } catch(e) {
        console.log("OCR verisi alınamadı, input kontrol ediliyor...");
        ocrText = $input.first().json.description || "";
    }
} catch (e) {
    console.log("Veri toplama hatası:", e);
}

const userNoteRule = userNote 
    ? `*** ÖZEL KULLANICI NOTU: Kullanıcı bu fiş için "${userNote}" notunu düştü. Eğer fiş genel bir harcamaysa bu notu kullan. Ancak satır bazında ürünler ayrışıyorsa, ürün isimlerine göre kategorilendir.` 
